impl Solution { pub fn network_becomes_idle(edges: Vec<Vec<i32>>, patience: Vec<i32>) -> i32 { let (n, mut black_adj) = (patience.len(), vec![vec![]; patience.len()]); for e in edges { black_adj[e[0] as usize].push(e[1] as usize); black_adj[e[1] as usize].push(e[0] as usize); } let (mut black_dist, mut black_q) = (vec![-1; n], std::collections::VecDeque::from([0])); black_dist[0] = 0; while let Some(u) = black_q.pop_front() { for &v in &black_adj[u] { if black_dist[v] == -1 { black_dist[v] = black_dist[u] + 1; black_q.push_back(v); } } } (1..n).map(|i| { let d = black_dist[i] * 2; d + (d - 1) / patience[i] * patience[i] }).max().unwrap_or(0) + 1 } }